              [PrioritisationCriterionValue].[PrioritisationCriterionId] = '39E305D8-7CB0-4F6D-9E88-822A622C0C1D'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		
			AND @PublichealthIrrelevanceFlag1 IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  
			  IF 
					@PublichealthIrrelevanceFlag1 = 'CBB4614A-4964-4CD1-8859-829D08CA3DFB'
				 BEGIN
			  SET @PrioritisationCriterionValueId = NULL
			  SET @IsMissing = 0
			  END
		

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
