		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Modal severity of human disease
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [HumanHealth] INNER JOIN [luModalSeverityLevel] ON [HumanHealth].[ModalSeverityOfHumanDisease] = [luModalSeverityLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luModalSeverityLevel].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = '36D7A0BD-FD41-4046-9531-B935EEC6A16D'
            

		  IF 
