              FROM
              [HumanHealthSpecies] INNER JOIN [luAttributableFraction] ON [HumanHealthSpecies].[AttributableFraction] = [luAttributableFraction].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luAttributableFraction].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = 'BC4C9E3A-39D6-44BE-8CB3-BE4A5FAC6DDD'
            

		  IF 
