		  SET @PrioritisationCriterionValueId = NULL

	  
        --Annual number of human cases of the disease in GB
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [HumanHealth] INNER JOIN [luHumanCasesLevel] ON [HumanHealth].[AnnualNumberOfHumanCasesInGB] = [luHumanCasesLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luHumanCasesLevel].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = '4E481036-517F-4F31-9C45-CFCB1DF23BC3'
            

		  IF 
