				 BEGIN
			  SET @PrioritisationCriterionValueId = NULL
			  SET @IsMissing = 0
			  END
		

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
		  [SpeciesId],
		  '4E481036-517F-4F31-9C45-CFCB1DF23BC3',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Indirect economic costs of human illness
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [HumanHealth] INNER JOIN [luCostLevel] ON [HumanHealth].[IndirectEconomicCostOfHumanIllness] = [luCostLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luCostLevel].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = '6E223561-31D8-466A-8714-D990CFE63A1A'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		
			AND @PublichealthIrrelevanceFlag1 IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  
			  IF 
					@PublichealthIrrelevanceFlag1 = 'CBB4614A-4964-4CD1-8859-829D08CA3DFB'
				 BEGIN
			  SET @PrioritisationCriterionValueId = NULL
			  SET @IsMissing = 0
			  END
		

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
