		  [SpeciesId],
		  '6E223561-31D8-466A-8714-D990CFE63A1A',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
      -- Riskandepidemiology
        --Uptake of control measures applied at the holding level by keepers of this species
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [ApproachToControlSpecies] INNER JOIN [luImpactLevel] ON [ApproachToControlSpecies].[UptakeAtHoldingLevel] = [luImpactLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luImpactLevel].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = 'B88F4BF0-3C2A-48AC-822C-0189C87B9C5B'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
