		  'B88F4BF0-3C2A-48AC-822C-0189C87B9C5B',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Rate of spread on and between affected premises
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [EpidemiologySpecies] INNER JOIN [luSpreadRateLevel] ON [EpidemiologySpecies].[RateOfSpreadOnPremises] = [luSpreadRateLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luSpreadRateLevel].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = '93FE637F-B831-4132-8A6B-1F71B803748A'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
		  [SpeciesId],
		  '93FE637F-B831-4132-8A6B-1F71B803748A',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Is there a reservoir in GB for this disease/agent in another species or vector
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [EpidemiologySpecies] INNER JOIN [luWildlifeReservoirIndicator] ON [EpidemiologySpecies].[WildlifeReservoirIndicator] = [luWildlifeReservoirIndicator].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luWildlifeReservoirIndicator].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = 'BA7F975A-684A-4148-8B2D-3A76DEDA3524'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
		  [SpeciesId],
		  'BA7F975A-684A-4148-8B2D-3A76DEDA3524',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Current holding level prevalence / Risk of introduction into animals in GB
        DECLARE @RE01MappingFlag bit
        
          
                SELECT
                @RE01MappingFlag = [GBPresenceIndicator]
                FROM
                [GeographicDistribution]
                WHERE
                [ProfileVersionId] = @ProfileVersionId
              

          IF @RE01MappingFlag = 1 BEGIN
        
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [GeographicDistribution] INNER JOIN [luPrevalenceLevel] ON [GeographicDistribution].[CurrentPrevalenceInGB] = [luPrevalenceLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luPrevalenceLevel].[LookupValue] = LEFT([PrioritisationCriterionValue].[CriterionValue], LEN([luPrevalenceLevel].[LookupValue]))
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = '09322102-9D62-4663-924D-5E70CDC1A8DD'
            
			END

			IF @RE01MappingFlag = 0 BEGIN

		
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [GeographicDistribution] INNER JOIN [luRiskLevel] ON [GeographicDistribution].[RiskOfIntroductionToGB] = [luRiskLevel].[Id]
              INNER JOIN [PrioritisationCriterionValue] ON [luRiskLevel].[LookupValue] = RIGHT([PrioritisationCriterionValue].[CriterionValue], LEN([luRiskLevel].[LookupValue]))
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = '09322102-9D62-4663-924D-5E70CDC1A8DD'
            
          
          END
          
        

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
		  [SpeciesId],
		  '09322102-9D62-4663-924D-5E70CDC1A8DD',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Potential for silent spread
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [EpidemiologySpecies] INNER JOIN [luImpactLevel] ON [EpidemiologySpecies].[PotentialForSilentSpread] = [luImpactLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luImpactLevel].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = '4CE1B0C9-F26B-4C92-B6B1-7C380A509966'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
		  [SpeciesId],
		  '4CE1B0C9-F26B-4C92-B6B1-7C380A509966',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Level of national preparedness or level of implementation for endemics/welfare issues
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [ApproachToControlSpecies] INNER JOIN [luImpactLevel] ON [ApproachToControlSpecies].[LevelOfNationalPreparedness] = [luImpactLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luImpactLevel].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = 'A3D947FA-2935-4AEE-96B0-A0AE6461C213'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
		  [SpeciesId],
		  'A3D947FA-2935-4AEE-96B0-A0AE6461C213',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Potential for risk change in animals in GB
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [GeographicDistributionSpecies] INNER JOIN [luRiskChange] ON [GeographicDistributionSpecies].[PotentialForRiskChange] = [luRiskChange].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luRiskChange].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = 'EFAA8531-EFE7-4CF0-A4B9-A3F507F58FF1'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
		  [SpeciesId],
		  'EFAA8531-EFE7-4CF0-A4B9-A3F507F58FF1',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Efficacy and practicality of control applied at the holding level
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [ApproachToControlSpecies] INNER JOIN [luImpactLevel] ON [ApproachToControlSpecies].[ControlsAtTheHoldingLevel] = [luImpactLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luImpactLevel].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = '5F1196DB-7CC8-45DB-93AB-AFD355DF841C'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
		  [SpeciesId],
		  '5F1196DB-7CC8-45DB-93AB-AFD355DF841C',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Efficacy of control measures to prevent dissemination in or between animals that are implemented above holding level
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [ApproachToControl] INNER JOIN [luImpactLevel] ON [ApproachToControl].[ControlsAboveTheHoldingLevel] = [luImpactLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luImpactLevel].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = 'D5E06EA0-8917-427C-81D1-DA362A557433'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
		  [SpeciesId],
		  'D5E06EA0-8917-427C-81D1-DA362A557433',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
      -- Welfare

			  DECLARE @WelfareIrrelevanceFlag1 bit
						  SELECT
						  @WelfareIrrelevanceFlag1 = [WelfareIssueIndicator]
						  FROM
						  [AnimalWelfareSpecies]
						  WHERE
						  [ProfileVersionId] = @ProfileVersionId AND
						  [SpeciesId] = @SpeciesId
					  
        --Number of clinical cases, at the modal severity, per year in GB
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [GeographicDistributionSpecies] INNER JOIN [luCasesPerYear] ON [GeographicDistributionSpecies].[NumberOfCasesPerYearInGB] = [luCasesPerYear].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luCasesPerYear].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = '4A685626-A7D4-4F81-BBC3-08F6E6C32003'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		
			AND @WelfareIrrelevanceFlag1 IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  
			  IF 
					@WelfareIrrelevanceFlag1 = 0 BEGIN
			  SET @PrioritisationCriterionValueId = NULL
			  SET @IsMissing = 0
			  END
		

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
