		  '4A685626-A7D4-4F81-BBC3-08F6E6C32003',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Impact on freedom to express normal behaviour
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [AnimalWelfareSpecies] INNER JOIN [luIssueExtent] ON [AnimalWelfareSpecies].[FreedomToExpressNormalBehaviour] = [luIssueExtent].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luIssueExtent].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = 'DBA652AB-BB4F-457E-8FBE-2C9109DD7E93'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		
			AND @WelfareIrrelevanceFlag1 IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
		  END
		  		  
		  
			  IF 
					@WelfareIrrelevanceFlag1 = 0 BEGIN
			  SET @PrioritisationCriterionValueId = NULL
			  SET @IsMissing = 0
			  END
		

		  INSERT INTO [ProfileVersionSpeciesPrioritisation]
		  (
		  [ProfileVersionId],
		  [SpeciesId],
		  [PrioritisationCriterionId],
		  [PrioritisationCriterionValueId],
		  [IsMissing]
		  )
		  SELECT
		  @ProfileVersionId,
		  [SpeciesId],
		  'DBA652AB-BB4F-457E-8FBE-2C9109DD7E93',
		  @PrioritisationCriterionValueId,
		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Welfare impact of likely or statutory control measures
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [ApproachToControlSpecies] INNER JOIN [luProportionLevel] ON [ApproachToControlSpecies].[WelfareEffect] = [luProportionLevel].[Id]
              
                  INNER JOIN [PrioritisationCriterionValue] ON [luProportionLevel].[LookupValue] = [PrioritisationCriterionValue].[CriterionValue]
                
              WHERE
              [ProfileVersionId] = @ProfileVersionId AND
              [SpeciesId] = @SpeciesId AND
              [PrioritisationCriterionValue].[PrioritisationCriterionId] = 'A14298BB-3C16-4DC1-94B7-3FB74F0ACDED'
            

		  IF 
		@PrioritisationCriterionValueId IS NOT NULL
		
			AND @WelfareIrrelevanceFlag1 IS NOT NULL
		 BEGIN
		  SET @IsMissing = 0
		  END ELSE BEGIN
		  SET @IsMissing = 1
