		  @IsMissing
		  FROM
		  @SpeciesList

		  SET @PrioritisationCriterionValueId = NULL

	  
        --Modal duration of welfare impact experienced by animals in GB
              SELECT
              @PrioritisationCriterionValueId = [PrioritisationCriterionValue].[Id]
              FROM
              [EpidemiologySpecies] INNER JOIN [luDiseaseDuration] ON [EpidemiologySpecies].[DurationOfDisease] = [luDiseaseDuration].[Id]
              
